var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"야…… 야! 거긴 진짜 안 돼!","JPN":"おい……アンタさ！　そこは本当にダメなんだって！","ENG":"Hey... Hey! You really can’t go in there!","TWN":"喂……喂！那邊真的不行啦！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"가야 돼.","JPN":"行かなきゃ。","ENG":"I need to go.","TWN":"我要去。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭘 들은 거야. 거기 들어가면 큰일난다니까?","JPN":"私の話聞いてた？　そこに入ったら大変なことになるんだってば。","ENG":"Didn’t you hear me? You’ll get in big trouble if you do!","TWN":"你沒聽見我說的嗎？靠近那裡會出事的！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"들키면 너도 저 방에 가두실 거야!","JPN":"バレたらアンタもあの部屋に閉じ込められるよ！","ENG":"You’ll also rot in there if you get caught!","TWN":"要是被發現，她也會把你關在那裡面喔！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"상관없어.","JPN":"関係ない。","ENG":"It doesn’t matter.","TWN":"我不怕。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……망했다. 문은 어떻게 연 거야?","JPN":"終わった……どうやって扉開けたんだろう？","ENG":"...Oh shoot. How did she even open the door?","TWN":"……完了，門是怎麼打開的？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니, 지금 그게 문제냐. 야!! 거기 서!","JPN":"いや、今はそれどころじゃない。おい！！　そこ待った！","ENG":"Wait, that’s not the problem right now! Hey!! Stop right there!","TWN":"不對，現在重點不是這個！喂！給我站住！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……네가 보고 싶었던 게 저 꼴이야?","JPN":"……アンタが見たかったのって、アレ？","ENG":"Did you want to see \\"that\\"...?","TWN":"……那就是你想看到的嗎？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"딱 봐도 최소 이틀 이상은 갇혀 있었네. 사람이 들어온 줄도 모르는 거 보면.","JPN":"パッと見、最低二日以上は閉じ込められてそうだね。人が来たのもわからない様子じゃあ。","ENG":"Looks like she’s been here for at least two days, judging by how she hasn’t even flinched at the sound of us coming in...","TWN":"看她那樣，應該至少被關了二天以上，而且連有人進來都沒發現……"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"기절…… 한 건가?","JPN":"気絶……してるのかな？","ENG":"Has she... fainted?","TWN":"是……暈過去了嗎？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"잠들었어.","JPN":"眠ってる。","ENG":"She’s asleep.","TWN":"是睡著了。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"하지만…… 많이 지쳐 보여.","JPN":"でも……すごく疲れてるみたい。","ENG":"But... She looks exhausted.","TWN":"不過……她看起來很疲憊。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그렇겠지. 여긴 벌받는 곳이니까.","JPN":"そうだろうね。ここはお仕置きされるところだから。","ENG":"You bet. This place is used for punishment.","TWN":"想也知道，這裡可是專門懲罰人的地方。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저 애, 반성만 하면 금방 돌려보내 줄 거니까 너도 이제 그만 돌아……","JPN":"あの子、反省さえすればすぐ戻されるんだから、アンタもいい加減……","ENG":"But she’ll be sent back after she’s repented. So you should head back to─","TWN":"只要她好好反省，很快就會被放出去的，你也趕快回……"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"?!","JPN":"！？","ENG":"?!","TWN":"？！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"걔는 왜 건드려! 얌전히 두고 나가자고!","JPN":"なに触ってるんだよ！　大人しくほっといて出ようってば！","ENG":"Hey, don’t touch her! Just leave, okay?!","TWN":"你幹嘛碰她啦！別管她，我們只要安靜地離開就好！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"가야 돼.","JPN":"行かなきゃ。","ENG":"I need to go.","TWN":"我要去。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"말만 간다, 간다 하지 말고 제발 좀 돌아가 주면 안 될까?","JPN":"口だけ行く行くって言わないで、本当に帰ってくれないかな？","ENG":"Stop saying that and just go back to your room already.","TWN":"拜託你不要一直說我要去、我要去，趕快回你的房間好嗎？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"들키면 너나 나나 끝장이야.","JPN":"バレたらアンタも、私も終わりなんだよ。","ENG":"We’re both dead meat if we get caught being here.","TWN":"被抓到的話，你跟我都會倒大楣的！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이러다 졸업생 최초로 이 방에 갇힌 사람이 될 수도 있다고……!","JPN":"このままじゃ卒業生の中でこの部屋に閉じ込められた最初の人になるかも……！","ENG":"Geez, I’ll be the first graduate to be stuck in the isolation chamber...!","TWN":"你不要害我變成第一個被關在這裡面的畢業生喔……！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"이 아이…… 악몽을 꾸고 있어.","JPN":"この子……悪夢をみてる。","ENG":"This girl... She’s having a nightmare.","TWN":"她……在做惡夢。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그야 당연하지. 여긴 위저드니까!","JPN":"そりゃ当たり前だろ。ここはウィザードなんだから！","ENG":"No wonder. This is Wizard!","TWN":"廢話，這裡可是魔法師欸！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"쟤도 꾸고, 나도 꾸고, 여기 있는 사람들은 모두 꾼다고!","JPN":"あの子も、私も、ここのみんな見てるし！","ENG":"She’s having nightmares, I’m having nightmares. We’re all having nightmares!","TWN":"何止是她會做惡夢，我也會做惡夢，在這裡的人都會做惡夢啦！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하! 그래. 말 더럽게 안 들으시겠다?","JPN":"は！　いいよ。言うこと聞かないつもりなんだね？","ENG":"Argh! All right. So you’re not gonna listen to me, are you?","TWN":"呼！好吧，耳朵要這麼硬是嗎？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"순순히 돌아가지 않겠다면 억지로라도 떼어내면 되지.","JPN":"素直に帰らないんなら、無理やり引きずり出せばいいだけ。","ENG":"Then I guess I’ll just have to drag you out by force!","TWN":"敬酒不吃，你要吃罰酒是吧！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 말 안 듣는 똥고집쟁이가 진짜……!","JPN":"この言うこと聞かない意地っ張りが……！","ENG":"Argh! Stop... Being... So... Stubborn...!","TWN":"你這不聽話的固執……！"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"뭐야? 어떤 놈들이 이렇게 시끄러워?","JPN":"何だ？　誰が騒いでるんだ？","ENG":"Huh? Who’s causing all that ruckus?!","TWN":"是誰？誰在那邊吵吵鬧鬧的？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"여긴 출입금지 구역이야. 문 앞에 대문짝만 하게 붙여 놨으니 몰랐을 리 없겠지.","JPN":"ここは出入り禁止区域だぞ。扉の前にでかく貼ってあるんだから知らないはずないよな。","ENG":"You’re not supposed to be here. Didn’t you see the \\"Do not enter\\" sign hanging on the door?","TWN":"這裡是禁止出入的，門上的字寫得清清楚楚，你們不可能沒看到吧？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하하핫, 야간 순찰 도시나 봐요? 이 밤중에 노고가 많으십니다.","JPN":"はははっ、夜間巡視ですか？　こんな夜中にご苦労さまです。","ENG":"Haha... On your nightly patrol, I see? Keep up the hard work!","TWN":"哈哈哈，你們是在夜間巡邏嗎？都這麼晚了，真是辛苦了。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"얘는 새로 들어온 앤데, 길을 헤매길래 방에 돌려보내려던 참이었답니다.","JPN":"この子新入りなんですけど、道に迷ってて部屋に連れていこうとしてました。","ENG":"I think she’s new here and got lost on her way back.","TWN":"她是新來的孩子，找不到路回房間，所以我正想帶她回去。"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 이제 돌아갈까, 루루?","JPN":"それじゃ、もう戻ろうか？　ルル。","ENG":"Now, Lulu, let’s get you back to your room.","TWN":"我們快回去吧，露露？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"응? 나?","JPN":"え？　私？","ENG":"Hmm? Me?","TWN":"嗯？我嗎？"},"stage":{"bg":"ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"음? 잠깐.","JPN":"む？　ちょっと待て。","ENG":"Huh? Wait a sec.","TWN":"嗯？先等一下。"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"저 애. 낯이 익은데?","JPN":"あの子。見覚えがあるぞ。","ENG":"I’ve seen that face somewhere before...","TWN":"她好像有點眼熟？"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"너무 저렴한 수법 아냐? 게다가 애한테 써먹기엔 네 나이가 좀 염치없지 않나?","JPN":"いつの時代のナンパなんだよ。それに子どもに使うにはお前の歳がちょっとあれなんじゃねえ？","ENG":"C’mon, what kind of cheesy pick-up line is that? Plus, that’s a kid you’re talking to!","TWN":"你這是什麼過時的搭訕法？而且以你的年紀，會不會太老牛吃嫩草啦？"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"무슨 헛소리야. 저 얼굴 분명 어디서 봤…… ","JPN":"何言ってるんだ。あの顔、確かどこかで見たこと…… ","ENG":"That’s not what I mean. I know I’ve seen her before...","TWN":"你在胡說八道什麼！她那張臉我分明在哪看過…… "},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"아!","JPN":"あ！","ENG":"Oh!","TWN":"我想起來了！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"수배범이잖아? 우리 조직 블랙 리스트에 오른 <color=#ffd34c>신원 미상의 침입자</color>!","JPN":"手配犯か！　ウチの組織のブラックリストに上がった<color=#ffd34c>身元不明の侵入者</color>！","ENG":"From the wanted poster! She’s the <color=#ffd34c>unidentified intruder</color> who got on our blacklist!","TWN":"她是通緝犯！在我們組織的黑名單中有她，就是<color=#ffd34c>來歷不明的入侵者</color>！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"잠깐, 진짜잖아! 어쩐지 낯이 익다 했어!","JPN":"ちょ、本当だ！　どうりで見覚えがあると思ったぜ！","ENG":"Wait a minute! You’re right! I knew I saw her face somewhere!","TWN":"等等，對欸！難怪我覺得很眼熟！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"수배범? 침입자……? 그게 무슨…….","JPN":"手配犯？　侵入者……？　それはどういう……","ENG":"Wanted poster? Intruder...? What the heck...?","TWN":"通緝犯？入侵者……？這是什麼……"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"현상금까지 걸린 녀석이야. 금액이 꽤 크던데.","JPN":"懸賞金までかかってる奴だ。金額も結構大きかったぜ。","ENG":"She’s even got a bounty on her head. The amount looks pretty good too.","TWN":"抓到她是有賞金的，而且數目還不小呢！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"어제 <color=#ffd34c>라스트 헤이븐</color>에서 탈탈 털렸었는데 잘 됐어.","JPN":"昨日<color=#ffd34c>ラストヘイブン</color>ですっからかんになったところだ。ありがてぇ。","ENG":"Yeah, I lost so much at <color=#ffd34c>Last Haven</color> last night. This is good.","TWN":"正好昨天在<color=#ffd34c>最後的天堂</color>錢包被榨乾，有這麼好的事！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"저 여자도 같이 잡아!","JPN":"あの女も一緒に捕まえろ！","ENG":"Get that other girl too!","TWN":"那女的也一起帶走吧！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"엥? 저는 왜요?!","JPN":"え？　私はなんで！？","ENG":"Huh? Why me too?!","TWN":"嗯？我嗎？為什麼？！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"수배범을 감싸 줬잖아? 아까 이름도 부르는 것 같던데.","JPN":"手配犯を庇ってやっただろ？　さっき名前も呼んでたしな。","ENG":"You were covering for this girl! You even called her by name!","TWN":"誰叫你藏匿通緝犯，而且你剛才還有叫她的名字不是嗎？"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"공범이 분명하군. 같이 잡아서 데려가지.","JPN":"共犯に違いない。一緒に捕まえて連れて行こう。","ENG":"That means you must be an accomplice. You’re coming with us.","TWN":"擺明是共犯，全都一起帶走！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그, 그게 오해가 있으신 모양인데요. 전 글린다라고, 며칠 전에 여기 배정받은 신입입니다만…….","JPN":"あ、あの、何か誤解してません？　私はグリンダっていって、何日か前からここの配属になった新入りですけど……","ENG":"U-um... There seems to have been a misunderstanding here. I’m Glinda, the new girl assigned here a few days a─","TWN":"誤…誤會誤會，我叫格琳達，幾天前剛來這裡報到的新人……"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"히익?! 미, 미쳤나 봐!","JPN":"ひいっ！？　じょ、冗談でしょ！","ENG":"Eek?! A-are you out of your mind?!","TWN":"哇啊？！神經病啊你們！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_FAKE","text":{"KOREA":"빈틈이다.","JPN":"隙あり。","ENG":"An opening.","TWN":"有漏洞。"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"잡아!","JPN":"捕まえろ！","ENG":"Get her!","TWN":"抓住她們！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"제길. 나도 모르겠다!","JPN":"くっそ。もう知らない！","ENG":"Crap! I dunno anymore!","TWN":"該死！隨便啦！"},"stage":{"bg":"ROOM","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……그래서. 놓쳤다는 건가요?","JPN":"……それで。逃がしたのですか？","ENG":"So... You lost them?","TWN":"……意思是，人跑了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ございません。","ENG":"...My apologies, Madam.","TWN":"……抱歉！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"처음으로 직접 모습을 보였는데 놓쳤다, 라…….","JPN":"初めて直接姿を現したのに逃した、と……","ENG":"She appeared herself for the first time, and you let her get away...","TWN":"她第一次現身，結果被她給跑了……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"그게 또 우리 잘못이라고 하기엔 애매한 감이 있습니다요.","JPN":"それが、またこちらのミスっていうにはちょっと曖昧なんすよ。","ENG":"Well, it wasn’t completely our fault...","TWN":"但這也不能全怪我們吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"마담 말대로 애가 여간 잽싼 게 아니더라고요. <color=#ffd34c>헤이븐 랜드</color>에서도 아주 신출귀몰했다던데?","JPN":"マダムの言う通り、めちゃくちゃ素早かったんです。<color=#ffd34c>ヘイブンランド</color>でも神出鬼没だったとか。","ENG":"The girl is wicked fast like you said, Madam. I heard it was like she just vanished into thin air at <color=#ffd34c>Havenland</color> too.","TWN":"照夫人的說法，她本來就身手矯健，在<color=#ffd34c>天堂樂園</color>也是神出鬼沒的？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그랬죠. CCTV에 모습은 찍혀 있는데, 아무도 본 사람은 없고.","JPN":"そうでしたね。防犯カメラには映っているのに、見た者は誰もいない。","ENG":"Sure enough. We have footage of her on our security cameras, but no one claims to have seen her.","TWN":"沒錯，雖然CCTV有拍到她，卻沒人真正見過她。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"밤마다 삼엄한 경비를 어떻게 뚫는지 매번 깊숙한 곳까지 침입하고.","JPN":"毎晩厳しい警戒をどうやってくぐり抜けたのか、いつも深いところまで侵入している。","ENG":"Plus, she somehow weasels her way through our tight security every time...","TWN":"她每晚都會突破森嚴的戒備，入侵到組織內部。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"무슨 꿍꿍이인지 몰라 더 위험한 인물인데…….","JPN":"なんのつもりなのかわからない分、さらに危険な人物と言えますが……","ENG":"She’s even more of a threat as we don’t know why she’s even doing this...","TWN":"而且也不知道她在打什麼主意，這樣反而更危險……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내부자 이름이 <color=#ffd34c>글린다</color>라고 했나요?","JPN":"内部の者の名前、<color=#ffd34c>グリンダ</color>と言いましたか？","ENG":"The other girl. Her name is <color=#ffd34c>Glinda</color>, you said?","TWN":"你說內部人員的名字叫<color=#ffd34c>格琳達</color>嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"그렇습니다.","JPN":"そうです。","ENG":"That's correct.","TWN":"是的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아. 어쩐지. 스파이가 있으니 경비도 피해서 들어올 수 있었겠네요.","JPN":"はあ。やっぱり。スパイがいるから警備を避けて入ってこれたのですね。","ENG":"Ugh... I see. So that’s how she’s been able to avoid all of our guards.","TWN":"哎呀，難怪，原來是有內鬼，難怪她可以輕易避開戒備。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"안 그럼 개미 한 마리 못 들어오는 삼엄한 방어벽을 어떻게 뚫었겠어요. 그렇죠?","JPN":"そうでないと、アリの這い入る隙もない厳重な防御壁をくぐり抜けられるわけがない。そうでしょう？","ENG":"How else would anyone be able to infiltrate our building without getting help from the inside, no?","TWN":"否則她怎麼可能突破銅牆鐵壁般的戒備呢？你們說是不是？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"넵. 지당하신 말씀이십니다.","JPN":"はい、ごもっともっす。","ENG":"Yes, Madam. You are right as always.","TWN":"是，夫人說得對。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드 졸업생이라던데. 어떤 식으로 배신자가 된 건지 알아봐 줘요.","JPN":"ウィザードの卒業生らしいけど。どうやって裏切り者になったのか調べてみてください。","ENG":"Isn’t she a Wizard graduate? Look into what made her betray us.","TWN":"我要請你們幫我查清楚，那個魔法師畢業生是怎麼背叛我們的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그리고…….","JPN":"それから……","ENG":"Also...","TWN":"還有……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"<color=#ffd34c>헤이븐</color> 님의 전언입니다.","JPN":"<color=#ffd34c>ヘイブン</color>様からの伝言です。","ENG":"These are orders from Mr. <color=#ffd34c>Haven</color>.","TWN":"<color=#ffd34c>天堂</color>先生要我轉告你們，"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"무슨 수를 써서라도 그 둘을 잡아오라고 하셨어요. 이번에도 놓치면 위저드 소속 지원팀의 능력을 의심할 수밖에 없다고요.","JPN":"どんな手を使ってでもあの二人を捕まえてこい、だそうです。今度も逃がしたら、ウィザード所属の応援班の能力を疑うしかないと。","ENG":"He has directed that we apprehend those two at all costs. Otherwise, the abilities of Wizard's support team will be called into question.","TWN":"無論如何，一定要把人抓回來，若再失手，那他就不得不質疑支援組的能力。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"물론 수배범들은 사지가 찢겨도 살아만 있으면 괜찮다고 말씀하셨습니다.","JPN":"もちろん手配犯たちは手足がちぎられていても、生きてさえいれば問題ないとおっしゃいました。","ENG":"He doesn't mind if they lose an arm or a leg as long as they're still alive.","TWN":"就算斷手斷腳都無所謂，只要人還能喘氣就好。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"임무 실패 시 지원팀 존폐 여부, 여러분의 신체 분리 여부에 대해서도 말씀하셨지만, 굳이 상세히 전하진 않을게요.","JPN":"任務に失敗した場合の応援班の存廃如何、また皆さんの身体の分離如何についてもお話がありましたが、詳しく伝えるのはやめておきましょう。","ENG":"Failure on this mission will determine the fate of the support team, and while he detailed what he'll do to all of you, I don't think sharing those details is necessary.","TWN":"他也有提到要是任務失敗，支援組的去留，或是你們的屍體要如何處理，但我想這部分就先保留。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SMILE_NPC_OZ_A","text":{"KOREA":"……꼭 잡아오겠습니다.","JPN":"……絶対捕まえてきます。","ENG":"...We won’t fail you again.","TWN":"……我們一定會把人抓回來的！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머~ 역시 든든해라. <color=#ffd34c>오즈 사건</color> 때도 살아남았다던 분들이 당신들이죠?","JPN":"まあ～やっぱり頼もしい。<color=#ffd34c>オズの事件</color>の時にも生き残ったというのはあなたたちですね？","ENG":"Oh my, I knew I could count on you. Are you all the ones who survived the <color=#ffd34c>OZ Incident</color> as well?","TWN":"哇喔～真是可靠。在<color=#ffd34c>奧茲國事件</color>中倖存下來的就是你們幾個吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드에 이런 인재들이 있는 줄은 몰랐네요. 진작 내려와서 살펴볼 걸 그랬어요.","JPN":"ウィザードにこんな人材がいるなんて、知りませんでした。もっと早く降りてきて確認するべきでしたね。","ENG":"I had no idea Wizard had such talented people. I should’ve come down much sooner!","TWN":"沒想到魔法師裡有這麼棒的人才，我應該早點下來會會你們的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SMILE_NPC_OZ_B","text":{"KOREA":"하핫. 워낙 바쁘신 거 다 아는데요, 뭐. 알아봐 주신 것만으로도 영광입니다요.","JPN":"ははっ。とてもお忙しいってことは知ってますよ。わかっていただいただけで光栄っす。","ENG":"Ha hah! We all know how busy you are. It’s an honor that you even noticed us.","TWN":"哈哈，大家都知道夫人很忙的，能被夫人賞識已經是莫大的榮幸！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SMILE_NPC_OZ_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼…… 이제 출발하셔야죠? 둘 다 어린 여자 애들이니, 멀리 가진 못했을 거예요.","JPN":"それでは……もう出発なさったら？　あの二人は若い女の子ですし、そう遠くまでは行ってないはずです。","ENG":"Well then... Shouldn’t you get back to work? Since you’re looking for two young girls, they couldn’t have gone far.","TWN":"那……就趕緊出發吧？兩個小女孩應該不至於跑太遠。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님이 더 이상 화내시지 않게, 잘 부탁해요?","JPN":"ヘイブン様がこれ以上お怒りにならないように、よろしく頼みますよ？","ENG":"Mr. Haven’s patience is wearing thin, so don’t mess this one up, okay?","TWN":"那就麻煩你們別再讓天堂先生生氣囉。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};